"use client";

import { motion } from "framer-motion";
import { Shield, Target, Zap, Globe, Users, TrendingUp } from "lucide-react";

export default function About() {
  const values = [
    {
      icon: <Globe className="w-6 h-6" />,
      title: "Nationwide Reach",
      description: "Extensive network covering prime locations across major cities, ensuring maximum visibility for your brand."
    },
    {
      icon: <Target className="w-6 h-6" />,
      title: "Targeted Impact",
      description: "Strategic placements designed to capture the right audience at the perfect moment in their daily journey."
    },
    {
      icon: <Zap className="w-6 h-6" />,
      title: "Dynamic Solutions",
      description: "From classic billboards to cutting-edge digital displays, offering versatile formats for any campaign."
    },
    {
      icon: <Users className="w-6 h-6" />,
      title: "Audience First",
      description: "Data-driven insights to understand audience behavior and optimize your advertising ROI."
    },
    {
      icon: <Shield className="w-6 h-6" />,
      title: "Premium Quality",
      description: "Impeccably maintained assets and high-resolution displays that reflect the premium nature of your brand."
    },
    {
      icon: <TrendingUp className="w-6 h-6" />,
      title: "Proven Results",
      description: "Decades of expertise delivering measurable success for local businesses and global enterprises alike."
    }
  ];

  return (
    <div className="relative min-h-screen bg-slate-50 text-slate-900 overflow-hidden">

      {/* Background Gradient */}
      <div className="absolute top-0 left-0 w-full h-[600px] bg-gradient-to-b from-white to-slate-50 z-0 pointer-events-none" />

      {/* Hero Section */}
      <section className="relative z-10 pt-32 pb-16 md:pt-40 md:pb-24">
        <div className="container mx-auto px-6 md:px-12">
          <div className="max-w-4xl mx-auto text-center">
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5 }}
              className="inline-flex items-center space-x-2 bg-white px-4 py-2 rounded-full shadow-sm border border-slate-200 mb-6"
            >
              <Globe className="w-4 h-4 text-brand-blue" />
              <span className="text-xs font-bold uppercase tracking-wider text-slate-700">
                Our Story
              </span>
            </motion.div>

            <motion.h1 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.1 }}
              className="text-4xl md:text-6xl font-black font-heading tracking-tight text-slate-900 mb-6 leading-tight"
            >
              Transforming Cityscapes into <span className="text-brand-blue">Brand Experiences</span>
            </motion.h1>

            <motion.p 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.2 }}
              className="text-lg md:text-xl text-slate-600 leading-relaxed mb-10"
            >
              At ApexOOH, we don't just sell ad space; we create landmarks. For over a decade, we have been at the forefront of out-of-home advertising, connecting brands with their audiences in the physical world through impactful, larger-than-life media.
            </motion.p>
          </div>
        </div>
      </section>

      {/* Mission & Vision */}
      <section className="relative z-10 py-16 bg-white border-y border-slate-100">
        <div className="container mx-auto px-6 md:px-12">
          <div className="grid md:grid-cols-2 gap-12 lg:gap-24 items-center">
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
              className="space-y-6"
            >
              <h2 className="text-3xl md:text-4xl font-bold font-heading text-slate-900">Our Mission</h2>
              <p className="text-slate-600 leading-relaxed text-lg">
                To empower brands to make bold statements in the real world. We strive to provide premium outdoor advertising solutions that are not only highly visible but also contextually relevant, elevating the urban environment while delivering exceptional value to our clients.
              </p>
            </motion.div>

            <motion.div 
              initial={{ opacity: 0, x: 20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: 0.2 }}
              className="space-y-6"
            >
              <h2 className="text-3xl md:text-4xl font-bold font-heading text-slate-900">Our Vision</h2>
              <p className="text-slate-600 leading-relaxed text-lg">
                To be the undisputed leader in out-of-home media innovation, seamlessly blending technology with physical structures to create immersive, data-driven, and sustainable advertising experiences that shape the future of urban communication.
              </p>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Core Values */}
      <section className="relative z-10 py-24">
        <div className="container mx-auto px-6 md:px-12">
          <div className="text-center max-w-3xl mx-auto mb-16">
            <h2 className="text-3xl md:text-4xl font-black font-heading text-slate-900 mb-6">The Apex Advantage</h2>
            <p className="text-slate-600 text-lg">
              What sets us apart in the competitive landscape of out-of-home advertising. We combine prime real estate with uncompromising quality.
            </p>
          </div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {values.map((value, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
                className="bg-white rounded-3xl p-8 border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300"
              >
                <div className="w-14 h-14 rounded-2xl bg-brand-blue/10 flex items-center justify-center text-brand-blue mb-6">
                  {value.icon}
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-4">{value.title}</h3>
                <p className="text-slate-600 leading-relaxed">
                  {value.description}
                </p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

    </div>
  );
}

"use client";

import { motion, useScroll, useTransform } from "framer-motion";
import { Shield, Target, Zap, Globe, Users, TrendingUp, MapPin, Building, Activity, ArrowRight, Linkedin, Twitter } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useRef } from "react";

export default function About() {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // Example parallax transform for the sticky section background
  const imgScale = useTransform(scrollYProgress, [0, 1], [1, 1.2]);

  const stats = [
    { value: "10+", label: "Years Experience", icon: <Activity className="w-5 h-5" /> },
    { value: "50+", label: "Cities Covered", icon: <MapPin className="w-5 h-5" /> },
    { value: "500+", label: "Campaigns Executed", icon: <Target className="w-5 h-5" /> },
    { value: "1B+", label: "Monthly Impressions", icon: <Users className="w-5 h-5" /> },
  ];

  const values = [
    {
      icon: <Globe className="w-6 h-6" />,
      title: "Nationwide Reach",
      description: "Extensive network covering prime locations across major cities, ensuring maximum visibility.",
      className: "md:col-span-2 md:row-span-2 bg-brand-blue text-white",
      iconClass: "bg-white/20 text-white",
      titleClass: "text-white",
      descClass: "text-blue-100"
    },
    {
      icon: <Target className="w-6 h-6" />,
      title: "Targeted Impact",
      description: "Strategic placements designed to capture the right audience at the perfect moment.",
      className: "bg-white text-slate-900",
      iconClass: "bg-brand-blue/10 text-brand-blue",
      titleClass: "text-slate-900",
      descClass: "text-slate-600"
    },
    {
      icon: <Zap className="w-6 h-6" />,
      title: "Dynamic Solutions",
      description: "From classic billboards to cutting-edge digital displays, offering versatile formats.",
      className: "bg-white text-slate-900",
      iconClass: "bg-brand-blue/10 text-brand-blue",
      titleClass: "text-slate-900",
      descClass: "text-slate-600"
    },
    {
      icon: <Users className="w-6 h-6" />,
      title: "Audience First",
      description: "Data-driven insights to understand audience behavior and optimize your advertising ROI.",
      className: "bg-slate-900 text-white",
      iconClass: "bg-white/10 text-brand-blue",
      titleClass: "text-white",
      descClass: "text-slate-400"
    },
    {
      icon: <Shield className="w-6 h-6" />,
      title: "Premium Quality",
      description: "Impeccably maintained assets and high-resolution displays reflecting premium brand standards.",
      className: "md:col-span-2 bg-white text-slate-900",
      iconClass: "bg-brand-blue/10 text-brand-blue",
      titleClass: "text-slate-900",
      descClass: "text-slate-600"
    }
  ];

  const team = [
    { name: "Sarah Jenkins", role: "Chief Executive Officer", initials: "SJ" },
    { name: "David Chen", role: "Head of Operations", initials: "DC" },
    { name: "Marcus Torres", role: "Director of Strategy", initials: "MT" },
  ];

  // Stagger variants for the Hero Title
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.2, delayChildren: 0.1 }
    }
  };

  const wordVariants = {
    hidden: { opacity: 0, y: 100 },
    visible: { 
      opacity: 1, 
      y: 0, 
      transition: { type: "spring", damping: 20, stiffness: 100 } 
    }
  };

  return (
    <div className="relative min-h-screen bg-slate-50 text-slate-900 overflow-hidden">

      {/* Cinematic Hero Section */}
      <section className="relative h-[90vh] min-h-[700px] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <Image 
            src="/images/hoarding.jpg" 
            alt="ApexOOH Premium Hoarding" 
            fill 
            className="object-cover scale-105 animate-slow-pan"
            priority
          />
          <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-slate-950/80 to-slate-950/40 mix-blend-multiply" />
          <div className="absolute inset-0 bg-brand-blue/20 mix-blend-overlay" />
        </div>

        <div className="container mx-auto px-6 md:px-12 relative z-10 text-center flex flex-col items-center mt-20">
          <motion.div
            initial={{ opacity: 0, y: -20, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className="inline-flex items-center space-x-2 bg-white/10 backdrop-blur-md px-5 py-2.5 rounded-full border border-white/20 mb-10 shadow-2xl"
          >
            <Building className="w-4 h-4 text-brand-blue" />
            <span className="text-xs font-bold uppercase tracking-wider text-white">
              Our Story
            </span>
          </motion.div>

          <motion.div 
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            className="flex flex-wrap justify-center overflow-hidden mb-8"
          >
            {["Pioneering", "Urban", "Media"].map((word, index) => (
              <motion.span 
                key={index}
                variants={wordVariants}
                className={`text-6xl md:text-8xl lg:text-9xl font-black font-heading tracking-tight inline-block mr-4 lg:mr-6 ${
                  word === "Urban" ? "text-transparent bg-clip-text bg-gradient-to-r from-brand-blue to-blue-400" : "text-white"
                }`}
              >
                {word}
              </motion.span>
            ))}
          </motion.div>

          <motion.p 
            initial={{ opacity: 0, filter: "blur(10px)" }}
            animate={{ opacity: 1, filter: "blur(0px)" }}
            transition={{ duration: 1, delay: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className="text-xl md:text-3xl text-slate-300 max-w-4xl mx-auto leading-relaxed font-light mt-4"
          >
            For over a decade, we have been at the forefront of out-of-home advertising, connecting brands with their audiences through larger-than-life experiences.
          </motion.p>
        </div>
      </section>

      {/* Stats Section - Floating above the transition */}
      <section className="relative z-20 -mt-24 px-6 md:px-12">
        <div className="container mx-auto">
          <motion.div 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, delay: 1, ease: [0.16, 1, 0.3, 1] }}
            className="bg-white/90 backdrop-blur-xl rounded-3xl p-8 md:p-12 shadow-[0_20px_50px_rgba(0,0,0,0.1)] border border-white flex flex-wrap justify-center md:justify-between gap-8 md:gap-4"
          >
            {stats.map((stat, i) => (
              <div key={i} className="flex flex-col items-center text-center px-4">
                <div className="text-brand-blue mb-4 bg-brand-blue/5 p-4 rounded-2xl shadow-inner">
                  {stat.icon}
                </div>
                <div className="text-4xl md:text-5xl font-black font-heading text-slate-900 mb-2 tracking-tight">{stat.value}</div>
                <div className="text-xs font-bold uppercase tracking-widest text-slate-400">{stat.label}</div>
              </div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* Mission & Vision - Sticky Scroll Section */}
      <section ref={containerRef} className="relative z-10 bg-slate-950 text-white mt-32">
        <div className="absolute top-0 right-0 w-full h-full bg-[url('/noise.png')] opacity-10 mix-blend-overlay pointer-events-none" />

        <div className="container mx-auto px-6 md:px-12 relative z-10">
          <div className="flex flex-col lg:flex-row relative">

            {/* Scrolling Text Content */}
            <div className="lg:w-1/2 py-24 lg:py-48 space-y-48 lg:space-y-[60vh]">

              <motion.div 
                initial={{ opacity: 0, x: -40 }}
                whileInView={{ opacity: 1, x: 0 }}
                viewport={{ once: true, margin: "-200px" }}
                transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
                className="relative"
              >
                <div className="absolute -top-16 -left-8 text-[12rem] font-black text-slate-800/40 -z-10 select-none leading-none">01</div>
                <h2 className="text-5xl md:text-7xl font-black font-heading text-white mb-8 relative z-10">Our Mission</h2>
                <p className="text-slate-400 leading-relaxed text-xl md:text-2xl font-light">
                  To empower brands to make bold statements in the real world. We strive to provide premium outdoor advertising solutions that are not only highly visible but also contextually relevant, elevating the urban environment while delivering exceptional value.
                </p>
              </motion.div>

              <motion.div 
                initial={{ opacity: 0, x: -40 }}
                whileInView={{ opacity: 1, x: 0 }}
                viewport={{ once: true, margin: "-200px" }}
                transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
                className="relative pb-24 lg:pb-48"
              >
                <div className="absolute -top-16 -left-8 text-[12rem] font-black text-slate-800/40 -z-10 select-none leading-none">02</div>
                <h2 className="text-5xl md:text-7xl font-black font-heading text-white mb-8 relative z-10">Our Vision</h2>
                <p className="text-slate-400 leading-relaxed text-xl md:text-2xl font-light">
                  To be the undisputed leader in out-of-home media innovation, seamlessly blending technology with physical structures to create immersive, data-driven, and sustainable advertising experiences that shape the future of urban communication.
                </p>
              </motion.div>

            </div>

            {/* Sticky Visuals Side */}
            <div className="hidden lg:block lg:w-1/2 h-screen sticky top-0 flex items-center justify-center p-12">
              <motion.div style={{ scale: imgScale }} className="relative w-full aspect-[4/5] rounded-[3rem] overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.5)]">
                <Image src="/images/highway.png" alt="Vision" fill className="object-cover opacity-60 grayscale mix-blend-luminosity" />
                <div className="absolute inset-0 bg-brand-blue/20 mix-blend-overlay" />

                {/* Floating Glass Panels within Sticky Container */}
                <div className="absolute top-1/4 left-8 bg-white/10 backdrop-blur-3xl border border-white/20 p-8 rounded-3xl w-72 shadow-2xl transform -rotate-3">
                  <Target className="w-10 h-10 text-brand-blue mb-4" />
                  <h4 className="text-2xl font-bold text-white mb-2 font-heading">Precision</h4>
                  <p className="text-slate-300">Data-backed locations for maximum ROI.</p>
                </div>
                <div className="absolute bottom-1/4 right-8 bg-white/10 backdrop-blur-3xl border border-white/20 p-8 rounded-3xl w-72 shadow-2xl transform rotate-3">
                  <TrendingUp className="w-10 h-10 text-brand-blue mb-4" />
                  <h4 className="text-2xl font-bold text-white mb-2 font-heading">Growth</h4>
                  <p className="text-slate-300">Scaling brand awareness exponentially.</p>
                </div>
              </motion.div>
            </div>
          </div>
        </div>
      </section>

      {/* Core Values - 3D Interactive Bento Grid */}
      <section className="relative z-10 py-32 bg-slate-50 border-t border-slate-200">
        <div className="container mx-auto px-6 md:px-12">
          <div className="text-center max-w-3xl mx-auto mb-24">
            <h2 className="text-4xl md:text-6xl font-black font-heading text-slate-900 mb-6">The Apex Advantage</h2>
            <p className="text-slate-600 text-xl font-light">
              What sets us apart in the competitive landscape of out-of-home advertising.
            </p>
          </div>

          {/* Added perspective for 3D tilt effect */}
          <div className="grid md:grid-cols-3 md:grid-rows-2 gap-6 auto-rows-fr perspective-[1200px]">
            {values.map((value, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                whileHover={{ scale: 1.02, rotateY: index % 2 === 0 ? 2 : -2, rotateX: 2 }}
                className={`group relative rounded-[2.5rem] p-8 md:p-10 border border-slate-200/60 shadow-lg hover:shadow-2xl transition-all duration-300 overflow-hidden flex flex-col justify-between ${value.className}`}
              >
                <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

                <div className="relative z-10">
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mb-8 shadow-sm transition-transform duration-500 group-hover:-translate-y-2 ${value.iconClass}`}>
                    {value.icon}
                  </div>
                  <h3 className={`text-3xl font-bold font-heading mb-4 ${value.titleClass}`}>{value.title}</h3>
                  <p className={`leading-relaxed text-lg font-light ${value.descClass}`}>
                    {value.description}
                  </p>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Leadership / Team Section */}
      <section className="relative z-10 py-32 bg-white">
        <div className="container mx-auto px-6 md:px-12">
          <div className="flex flex-col md:flex-row justify-between items-end mb-20 gap-8">
            <div className="max-w-2xl">
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                className="inline-flex items-center space-x-2 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 mb-6"
              >
                <span className="text-xs font-bold uppercase tracking-wider text-slate-700">
                  Our Leadership
                </span>
              </motion.div>
              <h2 className="text-4xl md:text-6xl font-black font-heading tracking-tight mb-6 text-slate-900">Meet the Team</h2>
              <p className="text-xl text-slate-500 font-light">The visionaries driving the future of urban media.</p>
            </div>
          </div>

          <div className="grid md:grid-cols-3 gap-12">
            {team.map((member, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.6, delay: index * 0.15 }}
                className="group cursor-pointer"
              >
                <div className="relative aspect-[3/4] mb-8 rounded-[2rem] overflow-hidden bg-gradient-to-br from-slate-200 to-slate-300">
                  {/* Placeholder for actual images */}
                  <div className="absolute inset-0 flex items-center justify-center text-7xl font-black text-slate-400/50 group-hover:scale-110 group-hover:text-brand-blue/20 transition-all duration-700">
                    {member.initials}
                  </div>
                  <div className="absolute inset-0 bg-slate-900/10 group-hover:bg-transparent transition-colors duration-500" />

                  {/* Social links overlay */}
                  <div className="absolute bottom-6 left-6 flex space-x-3 opacity-0 transform translate-y-4 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-500">
                    <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-900 hover:text-brand-blue shadow-lg">
                      <Linkedin className="w-4 h-4" />
                    </div>
                    <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-900 hover:text-brand-blue shadow-lg">
                      <Twitter className="w-4 h-4" />
                    </div>
                  </div>
                </div>
                <h3 className="text-3xl font-bold font-heading text-slate-900 mb-2">{member.name}</h3>
                <p className="text-lg text-brand-blue font-medium">{member.role}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="relative z-10 py-32 bg-brand-blue overflow-hidden">
        <div className="absolute inset-0 bg-[url('/noise.png')] opacity-20 mix-blend-overlay" />
        <div className="container mx-auto px-6 md:px-12 relative z-10 text-center">
          <h2 className="text-5xl md:text-7xl font-black font-heading text-white mb-8">Ready to make history?</h2>
          <p className="text-blue-100 text-xl md:text-2xl max-w-2xl mx-auto mb-12 font-light">
            Join the hundreds of brands that trust ApexOOH to elevate their presence in the physical world.
          </p>
          <Link href="/contact" className="inline-flex items-center justify-center px-12 py-6 text-brand-blue bg-white rounded-full font-bold text-xl hover:scale-105 transition-transform duration-300 shadow-[0_20px_50px_rgba(0,0,0,0.3)] group">
            <span>Contact Us Today</span>
            <ArrowRight className="ml-3 w-6 h-6 transition-transform group-hover:translate-x-2" />
          </Link>
        </div>
      </section>

      {/* Global CSS for custom animations */}
      <style dangerouslySetInnerHTML={{__html: `
        @keyframes slow-pan {
          0% { transform: scale(1.05) translate(0, 0); }
          50% { transform: scale(1.1) translate(-2%, 2%); }
          100% { transform: scale(1.05) translate(0, 0); }
        }
        .animate-slow-pan {
          animation: slow-pan 30s ease-in-out infinite;
        }
      `}} />

    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { Shield, Target, Zap, Globe, Users, TrendingUp, MapPin, Building, Activity, ArrowRight } from "lucide-react";
import Link from "next/link";
import { STATS } from "@/data";

export default function About() {
  const stats = [
    { value: "10", label: "Years Experience", icon: <Activity className="w-5 h-5" /> },
    { value: STATS.citiesCovered, label: "Cities Covered", icon: <MapPin className="w-5 h-5" /> },
    { value: STATS.campaignsExecuted, label: "Campaigns Executed", icon: <Target className="w-5 h-5" /> },
    { value: "1B", label: "Monthly Impressions", icon: <Users className="w-5 h-5" /> },
  ];

  const values = [
    {
      icon: <Globe className="w-6 h-6" />,
      title: "Nationwide Reach",
      description: "Extensive network covering prime locations across major cities, ensuring maximum visibility.",
    },
    {
